mapper.select:
SELECT
    p.*,
    COALESCE(NULLIF(u.username, ''), CONCAT('用户#', p.user_id)) AS author_name,
    u.avatar_url AS avatar_url
FROM community_post p
LEFT JOIN user u ON u.id = p.user_id

    AND COALESCE(p.visibility, 'public') = 'public'

        AND p.type = #{type}


        AND COALESCE(p.related_path_id, p.path_id) = #{pathId}


        AND p.chapter_id = #{chapterId}


        AND COALESCE(p.related_level_id, p.level_id) = #{levelId}


ORDER BY p.create_time DESC
LIMIT #{size} OFFSET #{page}

mapper.update:
UPDATE community_comment
SET content = #{content}, update_time = NOW()
WHERE id = #{id} AND user_id = #{userId}

